-- digital-fold-vardata-027-029-260630-dryrun.sql
-- 접지카드 027/029 접지비·가변비 저청구 교정 DRYRUN (ROLLBACK 전용·실 COMMIT 금지)
-- 권위: 인쇄상품 가격표 260527 / price-folding 시트 B01 카드접지 단가(오시+접지)
-- 엔진규칙: PRICE_TYPE.01 단가형 = unit_price × qty · _row_matches는 proc_cd 컬럼 매칭
BEGIN;

-- A. 접지비 2단 (027 2단접지카드): proc 065 2단가로 / 066 2단세로 → COMP_FOLD_LEAF_HALF

-- B. 접지비 3단 (029 3단접지카드): proc 067 3단가로 / 068 3단세로 → COMP_FOLD_LEAF_3FOLD

-- C. 가변 component 배선: COMP_PP_VARTEXT_1EA + COMP_PP_VARIMG_1EA (PRF_DGP_A 동형 모사)

-- 검증: 신규 접지 단가행 카운트(2단=96·3단=96) + 가변 배선 4행
SELECT 'fold_2dan' k, COUNT(*) FROM t_prc_component_prices WHERE comp_cd='COMP_FOLD_LEAF_HALF' AND proc_cd IN ('PROC_000065','PROC_000066')
UNION ALL SELECT 'fold_3dan', COUNT(*) FROM t_prc_component_prices WHERE comp_cd='COMP_FOLD_LEAF_3FOLD' AND proc_cd IN ('PROC_000067','PROC_000068')
UNION ALL SELECT 'var_wire', COUNT(*) FROM t_prc_formula_components WHERE frm_cd IN ('PRF_DGP_E','PRF_DGP_E_FOIL') AND comp_cd LIKE '%VAR%';

ROLLBACK;  -- 검증 전용 · 실 적재는 인간 승인 후 §7 dbmap 트랙
